template:
// --- PARETO ANALYSIS ({{dimensionField}} by {{measureField}}) [Fact: {{factTable}}] ---
[Temp_Pareto_Prep_{{factTable}}]:
LOAD [{{keyField}}], [{{measureField}}] RESIDENT [{{factTable}}];
LEFT JOIN ([Temp_Pareto_Prep_{{factTable}}])
LOAD [{{keyField}}], [{{dimensionField}}] RESIDENT [{{linkTable}}];

[Temp_Pareto_Agg_{{factTable}}]:
NOCONCATENATE
LOAD [{{dimensionField}}], Sum([{{measureField}}]) AS _SumMeasure RESIDENT [Temp_Pareto_Prep_{{factTable}}] GROUP BY [{{dimensionField}}];
DROP TABLE [Temp_Pareto_Prep_{{factTable}}];

[Temp_Pareto_Total_{{factTable}}]: LOAD Sum(_SumMeasure) AS _Total RESIDENT [Temp_Pareto_Agg_{{factTable}}];
LET vParetoTotal_{{factTable}} = Peek('_Total', 0, 'Temp_Pareto_Total_{{factTable}}');
DROP TABLE [Temp_Pareto_Total_{{factTable}}];

[Temp_Pareto_Sorted_{{factTable}}]:
NOCONCATENATE
LOAD [{{dimensionField}}], [_SumMeasure] RESIDENT [Temp_Pareto_Agg_{{factTable}}] ORDER BY [_SumMeasure] DESC;
DROP TABLE [Temp_Pareto_Agg_{{factTable}}];

[Pareto_{{factTable}}_{{dimensionField}}]:
NOCONCATENATE
LOAD
    [{{dimensionField}}],
    If(RangeSum([_SumMeasure], Peek('_AccMeasure')) / $(vParetoTotal_{{factTable}}) <= 0.8, Dual('Top 80%', 1), Dual('Bottom 20%', 0)) AS [{{dimensionField}}_Pareto_{{factTable}}_Flag],
    RangeSum([_SumMeasure], Peek('_AccMeasure')) AS _AccMeasure
RESIDENT [Temp_Pareto_Sorted_{{factTable}}];

DROP TABLE [Temp_Pareto_Sorted_{{factTable}}];
DROP FIELD [_AccMeasure] FROM [Pareto_{{factTable}}_{{dimensionField}}];

// --- DUAL FLAG INJECTION ---
[Enrich_Temp_{{fieldName}}]:
NOCONCATENATE
LOAD *, Dual([{{fieldName}}], Match([{{fieldName}}], {{mappingPairs}})) AS [{{fieldName}}_Dual]
RESIDENT [{{targetTable}}];

DROP TABLE [{{targetTable}}];
RENAME TABLE [Enrich_Temp_{{fieldName}}] TO [{{targetTable}}];
